import { createNavigationContainerRef } from '@react-navigation/native';
import { PropsRootStack } from './Models';

export const navigatorRef = createNavigationContainerRef<PropsRootStack>();

export function navigate(name: never, params: never) {
  if (navigatorRef.isReady()) {
    navigatorRef.navigate(name, params);
  }
}

